2799	\begin{lemma}[Restriction of sheaves of modules along an open immersion]
2800	  \label{lem:modules_restrictFunctor_mathlib}
2801	  \lean{AlgebraicGeometry.Scheme.Modules.restrictFunctor}
2802	  \mathlibok
2803	  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Modules.Sheaf}).}
2804	  For an open immersion \(f : X \to Y\), Mathlib supplies the restriction functor
2805	  \(f^{\mathrm{res}} : Y.\mathrm{Modules} \to X.\mathrm{Modules}\), with
2806	  \(\Gamma(f^{\mathrm{res}} M, U) = \Gamma(M, f(U))\) definitionally; it is a left adjoint (colimit
2807	  preserving) and carries the unit sheaf to the unit sheaf. This is the geometric
2808	  ``restrict to open \(U\)'' functor on \((\Spec R).\mathrm{Modules}\).
2809	\end{lemma}
